//!run
import {loadedModules} from "petit-node";
export async function main(){
    let r=new Set();
    for(let m of loadedModules()){
      if (m.path.match(/\/node_modules\//)) {
        const [a,b]=m.path.split("/node_modules/");
        const [n,s]=b.split("/",2);
        let p;
        if (n.match(/^@/)) {
          p=(n+"/"+s);
        } else{
          p=(n);
        }
        if (this.resolve(p).rel("package.json").exists()) {
          r.add(p);
        }
      }  
    }
//      const r=await fetch("https://registry.npmjs.org/petit-node/-/petit-node-1.6.9.tgz");
    for (let p of r){
      try{
        const res=await fetch(`https://registry.npmjs.org/${p}`);
        const j=await res.json();
        console.log(j);
        if (j.error) throw new Error(j.error); 
      }catch(e){
        this.echo(p); 
      }
    }
    //r.sort();
    //this.echo([...r].join("\n"));

}